"""Хранилище конфигурации модуля llm_models_registry (инициализируется при boot)."""from __future__ import annotationsfrom dataclasses import dataclassfrom pathlib import Path@dataclass(frozen=True)class ModuleConfig:    """Параметры модуля: путь к файлу реестра моделей (user store)."""    models_store_file: Pathclass ModuleConfigStore:    """Единая точка доступа к runtime-конфигурации модуля."""    _config: ModuleConfig | None = None    @classmethod    def set(cls, config: ModuleConfig) -> None:        cls._config = config    @classmethod    def get(cls) -> ModuleConfig:        if cls._config is None:            raise RuntimeError("llm_models_registry module is not initialized")        return cls._config    @classmethod    def reset(cls) -> None:        cls._config = None